<template>
  <div>
    <br>
<span>*********  语音识别   ************</span><br>	
	<input type='button' @click='microApp()' value='语音识别'></input>	   
<br>


<span>*********  蓝牙   ************</span><br>	
	<input type='button' @click='initialize()' value='初始化'></input><br>	
<!--<input type='button' @click='initialize()' value='启用'></input></br></br>
<input type='button' @click='initialize()' value='停用'></input></br></br>
<input type='button' @click='initialize()' value='获取适配器信'></input></br></br>-->
<input type='button' @click='startScan()' value='开始扫描'></input><br>	
<input type='button' @click='stopScan()' value='停止扫描'></input><br>	
<input type='button' @click='connect()' value='连接'></input><br>	
<input type='button' @click='reconnect()' value='断开'></input><br>	

<br>



	<br>
	<br>
<br>
  </div>
</template>

<script>
export default {
  name: "speech", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    /**

	微应用跳转
	参数说明：
		appCode				目标应用 应用编码 

**/

    microApp() {
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        console.log("执行到这边表示cordova环境没有准备好");
        return;
      }
      alert("安装 全流程监控 应用");
      try {
        mam.navigator.go.microApp(
          this.successCallback,
          this.errorCallback,
          "SNINTQLCJK"
        );
      } catch (ex) {
        console.log("try: " + ex.message);
      }
    },

    /**
	成功 回调
	参数说明：
		successCallback		成功回调	"code":0 成功	-2 应用不存在
**/
    successCallback(obj) {
      console.log(JSON.stringify(obj));
    },
    /**
	失败 回调
	参数说明：
		errorCallback		失败回调	"code":-1 参数错误 -3 内部错误(errorcallback)
**/
    errorCallback(obj) {
      mam.navigator.go.microApp(
        this.successCallback,
        this.errorCallback,
        "SNINTQLCJK"
      );
    },

    /**
	蓝牙
**/
    initialize() {
      var params = {
        request: true,
        statusReceiver: false,
        restoreKey: "bluetoothleplugin",
      };
      mam.navigator.bluetooth.initialize(blSuccessCallback, params);
    },

    startScan() {
      var params = {
        services: ["180D", "180F"],
        allowDuplicates: true,
        scanMode: bluetoothle.SCAN_MODE_LOW_LATENCY,
        matchMode: bluetoothle.MATCH_MODE_AGGRESSIVE,
        matchNum: bluetoothle.MATCH_NUM_MAX_ADVERTISEMENT,
        callbackType: bluetoothle.CALLBACK_TYPE_ALL_MATCHES,
      };
      mam.navigator.bluetooth.startScan(
        this.blSuccessCallback,
        this.blerrorCallback,
        params
      );
    },
    stopScan() {
      mam.navigator.bluetooth.stopScan(
        this.blSuccessCallback,
        this.blerrorCallback
      );
    },

    blSuccessCallback(obj) {
      console.log(JSON.stringify(obj));
    },
    blerrorCallback(obj) {
      console.log(JSON.stringify(obj));
    },
  },
};
</script>
